const fs = require('fs');
const path = require('path');

const basePath = 'C:\\Users\\LuizFerreira\\Local Sites';
const sites = [];

try {
  const dirs = fs.readdirSync(basePath);

  for (const dir of dirs) {
    const sitePath = path.join(basePath, dir);
    const stat = fs.statSync(sitePath);

    if (stat.isDirectory()) {
      const publicPath = path.join(sitePath, 'app', 'public');
      const wpConfig = path.join(publicPath, 'wp-config.php');

      if (fs.existsSync(wpConfig)) {
        // Extrai versão do WP
        let wpVersion = '?';
        try {
          const versionFile = fs.readFileSync(path.join(publicPath, 'wp-includes', 'version.php'), 'utf-8');
          const match = versionFile.match(/\$wp_version\s*=\s*['"]([^'"]+)['"]/);
          if (match) wpVersion = match[1];
        } catch {}

        // Extrai tema
        let theme = '?';
        try {
          const themePath = path.join(publicPath, 'wp-content', 'themes');
          if (fs.existsSync(themePath)) {
            const themes = fs.readdirSync(themePath).filter(f => {
              try { return fs.statSync(path.join(themePath, f)).isDirectory(); } catch { return false; }
            });
            theme = themes[0] || '?';
          }
        } catch {}

        sites.push({
          name: dir,
          path: sitePath,
          domain: dir + '.local',
          wpVersion,
          themeName: theme,
          isValid: true
        });
      }
    }
  }
} catch (e) {
  console.error('Erro:', e.message);
}

return [{ json: { sites } }];

